solution_code:
#include <iostream>

char gradeLetter(int score)
{
    if (score >= 90)
        return 'A';
    else if (score >= 80)
        return 'B';
    else if (score >= 70)
        return 'C';
    else if (score >= 60)
        return 'D';
    else
        return 'F';
}

int main()
{
    int score {};
    std::cin >> score;
    std::cout << gradeLetter(score) << '\n';
    return 0;
}
